#!/usr/bin/env python3r"""Plot a Google Benchmark JSON run as a grouped vertical bar chart.Usage:    python plot_bench.py <results.json> [-o out] [--metric items_per_second]                         [--filter REGEX] [--split REGEX]By default benchmark names are split on the last '/' into "<category>/<series>",so registrations like  vec4_add/nme  vec4_add/glm  become grouped bars per op.When the compared thing is NOT the trailing name segment (e.g. allocatorbenchmarks named BM_Tight_Malloc/bytes:16, where the allocator is what you wantto compare), use --split with a regex containing named groups (?P<cat>...) and(?P<ser>...) to say which token is the x-axis category and which is the colouredseries. Names that don't match --split are dropped, so --split also selects anexperiment; --filter REGEX narrows further. Examples:    # tight loop: category = block size, series = allocator    --split 'BM_Tight_(?P<ser>\w+)/(?P<cat>bytes:\d+)'    # batch: category = N x block size, series = allocator    --split 'BM_Batch_(?P<ser>\w+)/(?P<cat>N:\d+/bytes:\d+)'With --benchmark_report_aggregates_only the median aggregate is the plottedvalue and the stddev aggregate (if present) is drawn as error bars -- run with--benchmark_repetitions=N to get it. Saves <out>.png and <out>.svg. Uses a logy-axis automatically when the value range spans more than ~30x."""import argparse, json, re, sysfrom collections import OrderedDictimport matplotlibmatplotlib.use("Agg")import matplotlib.pyplot as pltimport numpy as npPALETTE = ["#2a78d6", "#1baf7a", "#eda100", "#4a3aa7", "#e34948", "#eb6834"]def load(path, metric, filt):    with open(path) as f:        entries = json.load(f)["benchmarks"]    filt_re = re.compile(filt) if filt else None    vals, errs = {}, {}  # run_name -> median value / stddev    for e in entries:        name = e.get("run_name", e["name"])        if filt_re and not filt_re.search(name):            continue        agg = e.get("aggregate_name")        # aggregates run: keep median (value) + stddev (error); drop mean/cv.        # raw runs have no aggregate_name -> value.        if e.get("run_type") == "aggregate" and agg not in ("median", "stddev"):            continue        if metric in e:            (errs if agg == "stddev" else vals)[name] = e[metric]    return vals, errsdef cat_ser(name, split_re):    """Return (category, series) for a run_name, or None to drop it."""    if split_re:        m = split_re.search(name)        if not m:            return None        return m.group("cat"), m.group("ser")    cat, _, s = name.rpartition("/")    return (cat or name), sdef main():    ap = argparse.ArgumentParser()    ap.add_argument("json")    ap.add_argument("-o", "--out", default="bench")    ap.add_argument("--metric", default="items_per_second")    ap.add_argument("--title", default="benchmark throughput")    ap.add_argument("--filter", help="regex; keep only matching run_names")    ap.add_argument("--split", help="regex with (?P<cat>) and (?P<ser>) groups")    args = ap.parse_args()    split_re = re.compile(args.split) if args.split else None    vals, errs = load(args.json, args.metric, args.filter)    if not vals:        sys.exit(f"no '{args.metric}' values found in {args.json}")    # category -> {series: (value, run_name)}   (run_name kept for error lookup)    cats, series = OrderedDict(), OrderedDict()    for name, v in vals.items():        cs = cat_ser(name, split_re)        if cs is None:            continue        cat, s = cs        cats.setdefault(cat, {})[s] = (v, name)        series.setdefault(s, None)    if not cats:        sys.exit("no rows matched --split; check the regex groups (?P<cat>/?P<ser>)")    cat_names, ser_names = list(cats), list(series)    scale = 1e6 if args.metric == "items_per_second" else 1.0  # -> millions    def val(c, s): return cats[c].get(s, (0, None))[0] / scale    def err(c, s):        rn = cats[c].get(s, (0, None))[1]        return (errs.get(rn, 0.0) / scale) if rn else 0.0    data = np.array([[val(c, s) for c in cat_names] for s in ser_names])    earr = np.array([[err(c, s) for c in cat_names] for s in ser_names])    has_err = earr.any()    fig, ax = plt.subplots(figsize=(max(6, 1.6 * len(cat_names)), 5))    x = np.arange(len(cat_names))    w = 0.8 / max(1, len(ser_names))    for i, s in enumerate(ser_names):        off = (i - (len(ser_names) - 1) / 2) * w        bars = ax.bar(x + off, data[i], w, color=PALETTE[i % len(PALETTE)],                      label=s, zorder=3,                      yerr=(earr[i] if has_err else None),                      capsize=2, error_kw={"elinewidth": 0.8, "zorder": 4})        ax.bar_label(bars, fmt="%.0f", padding=2, fontsize=8, color="#333")    hi, lo = data[data > 0].max(), data[data > 0].min()    if hi / lo > 30:        ax.set_yscale("log")    ax.set_xticks(x)    longlabels = max((len(c) for c in cat_names), default=0) > 12    ax.set_xticklabels(cat_names, fontsize=9,                       rotation=(30 if longlabels else 0),                       ha=("right" if longlabels else "center"))    unit = "million ops / s" if args.metric == "items_per_second" else args.metric    ax.set_ylabel(f"{unit}  (higher is better)", fontsize=10)    ax.set_title(args.title, fontsize=12, loc="left")    ax.grid(axis="y", color="#e1e0d9", zorder=0); ax.set_axisbelow(True)    for sp in ("top", "right"):        ax.spines[sp].set_visible(False)    ax.legend(frameon=False, ncol=len(ser_names), fontsize=9,              loc="upper center", bbox_to_anchor=(0.5, 1.12))    ax.margins(y=0.15)    plt.tight_layout()    for ext in ("png", "svg"):        fig.savefig(f"{args.out}.{ext}", dpi=150, bbox_inches="tight")    print(f"wrote {args.out}.png and {args.out}.svg")if __name__ == "__main__":    main()